sql:
SELECT model_name
FROM predictions
WHERE prediction_id = 0;

external_knowledge:
- 'significant performance indicators' refers to metrics with values greater than 100,000;
- 'notable threshold' in the question represents the threshold of 100,000 set for performance metrics;
- 'investors' refers to 'users' in the database context.

sql:
SELECT COUNT(DISTINCT user_id)
FROM portfolios
WHERE total_return > 0.2;

SELECT strategy_name, total_return
FROM backtests
WHERE stock_id = 1;

SELECT user_id, MAX(total_return) AS highest_total_return
FROM portfolios
GROUP BY user_id;

SELECT company_name, stock_symbol
FROM stocks
WHERE market_cap > (SELECT AVG(market_cap) FROM stocks);

SELECT COUNT(DISTINCT stock_id) AS unique_stocks_traded
FROM trades
WHERE user_id = 0;
